text:
&-subtitle {
  margin-top: @v-spacing-standard;
  margin-top: var(--am-coupon-subTitle-marginTop, @v-spacing-standard);
  font-size: @font-size-content;
  font-size: var(--am-coupon-subtitle-size, @font-size-content);
  color: @color-text-subtitle;
  color: var(--am-coupon-subtitle-color, @color-text-subtitle);
}

&-btn {
  color: @color-text-primary;
  color: var(--am-amount-btn-font-color, @color-text-primary);
  line-height: @line-height-base;
  line-height: var(--am-amount-btn-line-height, @line-height-base);
  font-size: @font-size-subtitle;
  font-size: var(--am-amount-btn-font-size, @font-size-subtitle);
}

&-title {
  line-height: @line-height-base;
  line-height: var(--am-amount-title-line-height, @line-height-base);
  color: @color-text-title;
  color: var(--am-amount-title-color, @color-text-title);
  font-size: @font-size-list;
  font-size: var(--am-amount-title-font-size, @font-size-list);
}

&-week {
  margin-bottom: @v-spacing-large;
  margin-bottom: var(--am-calendar-week-marginTB, @v-spacing-large);
  display: flex;
  flex-direction: row;
  padding: 0 @h-spacing-large;
  padding: 0 var(--am-calendar-week-paddingLR, @h-spacing-large);
}

&-description {
  width: min-content;
  padding: 0 8px;
  border-radius: 10px;
  color: var(--adm-color-weak);
  font-size: var(--adm-font-size-main);
  background-color: var(--adm-color-fill-content);
}

path[fill="#667B99"], // dark
    path[fill="#6F839F"], // dim
    [style*="color: rgb(111, 131, 159)"], // dark
    [style*="color: rgb(111, 131, 159)"] // dim
    {
      color: @subtext1 !important;
      fill: @subtext1 !important;
    }

path {
  .replaceColor(#B8D7FF, fill);
  .replaceColor(#8F69FF, fill);
  .replaceColor(#6D4AFF, fill);
  .replaceColor(#FFBB93, fill);
  .replaceColor(#85D4F5, fill);
  .replaceColor(#D6F1FC, fill);
}

&::before {
  content: '';
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--r-magenta);
  box-shadow: 0 0 8px var(--r-magenta);
  animation: respawn-pulse 1.6s ease-in-out infinite;
}

h1 {
  display: inline-block;
  vertical-align: middle;
  font-size: 20px;
  margin: 0 0 0 12px;
  font-family: 'Myriad Pro', 'Helvetica Neue', Arial, Helvetica, sans-serif;
  font-weight: 400;
}

@font-face {
    font-family: 'argon';
    src: url('../fonts/argon.woff2') format('woff2'),
        url('../fonts/argon.woff') format('woff');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
}

&::before {
  background:    url('atom://seti-ui/icons/project.svg') no-repeat;
  content:       '';
  height:        24px;
  margin-bottom: -7px;
  width:         30px;
  margin-right:  -5px;
}

#write .md-fences:not([class*=md-fences-math]):not([class*=md-diagram]) {
    color: var(--df);
    font-family: var(--v-fm-code);
    font-size: .875em;
    border-radius: var(--c-br-b);
    border: @codeblockBorderWidth solid var(--std-code-sd);
    margin: @paragraphPadding 0 0;
}

@font-face {
  font-weight: 400;
  font-family: AlibabaSans;
  font-style: normal;
  src: url('//mdn.alipayobjects.com/huamei_iwk9zp/afts/file/A*2zEUQqnPNesAAAAAQtAAAAgAegCCAQ/AlibabaSans-Regular.woff2')
    format('woff2');
  font-display: swap;
}

@font-face {
  font-weight: 300;
  font-family: AlibabaSans;
  font-style: normal;
  src: url('//mdn.alipayobjects.com/huamei_iwk9zp/afts/file/A*1GSgSYDD_aIAAAAAQsAAAAgAegCCAQ/AlibabaSans-Light.woff2')
    format('woff2');
  font-display: swap;
}

&-count-sm {
  min-width: @badge-height-sm;
  height: @badge-height-sm;
  padding: 0;
  font-size: @badge-font-size-sm;
  line-height: @badge-height-sm;
  border-radius: (@badge-height-sm / 2);
}

& &__role {
  display: inline-block;
  color: var(--tv-UserContact-role-info-text-color);
  margin-left: 8px;
  vertical-align: middle;
  font-size: var(--tv-UserContact-role-info-font-size);
  line-height: 1.5;
}

&__range {
  border-radius: var(--tv-Slider-range-border-radius);
  position: absolute;
  z-index: 1;
  margin-top: 0;
  height: var(--tv-Slider-range-height);
  background: var(--tv-Slider-range-bg-color);
}

& &__bottom-text {
  position: relative;
  font-size: var(--tv-Rate-bottom-font-size);
  text-align: center;
  text-overflow: clip;
  overflow: hidden;
  margin-top: var(--tv-Rate-bottom-margin-top);
}

&__mark-point {
  position: absolute;
  pointer-events: none;
  transform: translateX(-50%);
  width: 2px;
  height: var(--tv-Slider-height);
  background-color: var(--tv-Slider-mark-point-bg-color);
}

&-av,
    &-line {
      background: linear-gradient(90deg,
        rgba(255, 255, 255, 0.05) 25%,
        rgba(255, 255, 255, 0.10) 50%,
        rgba(255, 255, 255, 0.05) 75%);
      background-size: 800px 100%;
    }

code {
  font-family: "JetBrains Mono", "Fira Code", "Courier New", monospace;
  font-size: 13px;
  background: var(--avocado-surface-1);
  border-radius: 4px;
  padding: 2px 6px;
  color: var(--disc-title);
}

ral Typography
// ------------------------------------------------------------------------------
blockquote {
	color: @md-colors-quotes;
	margin: 0;
	padding-left: 1.5em;
	border-left: 0.5em mix(@md-colors-quotes, @md-colors-background, 25%) solid;
}

&:active {
  top: 10px;
  background-color: @color;

  -webkit-box-shadow: inset 0 1px 0 @color, inset 0 -3px 0 @keyHoverColor;
  -moz-box-shadow: inset 0 1px 0 @color, inset 0 -3pxpx 0 @keyHoverColor;
  box-shadow: inset 0 1px 0 @color, inset 0 -3px 0 @keyHoverColor;
}

&--tag {
  //width: 100%;
  text-align: center;
  padding: 0 16px;
  line-height: @tab-item-tag-height;
  border-radius: calc(@tab-item-tag-height / 2);
  background-color: @tab-item-tag-bg;
}

@media (min-width: @breakpoint-medium) {

    .uk-flex-stretch\@m { align-items: stretch; }
    .uk-flex-top\@m { align-items: flex-start; }
    .uk-flex-middle\@m { align-items: center; }
    .uk-flex-bottom\@m { align-items: flex-end; }

}

@media (min-width: @breakpoint-large) {

    .uk-flex-stretch\@l { align-items: stretch; }
    .uk-flex-top\@l { align-items: flex-start; }
    .uk-flex-middle\@l { align-items: center; }
    .uk-flex-bottom\@l { align-items: flex-end; }

}

@media (min-width: @breakpoint-small) {

    .uk-flex-stretch\@s { align-items: stretch; }
    .uk-flex-top\@s { align-items: flex-start; }
    .uk-flex-middle\@s { align-items: center; }
    .uk-flex-bottom\@s { align-items: flex-end; }

}

&__subname {
  width: 100%;
  margin-top: var(--van-padding-xs);
  color: var(--van-action-sheet-subname-color);
  font-size: var(--van-action-sheet-subname-font-size);
  line-height: var(--van-action-sheet-subname-line-height);
  overflow-wrap: break-word;
}

&__loading,
  &__finished-text,
  &__error-text {
    color: var(--van-list-text-color);
    font-size: var(--van-list-text-font-size);
    line-height: var(--van-list-text-line-height);
    text-align: center;
  }

&__bar {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  height: var(--van-submit-bar-height);
  padding: var(--van-submit-bar-padding);
  font-size: var(--van-submit-bar-text-font-size);
}
